import { useEffect, useMemo } from 'react'

/**
 * Injects JSON-LD from CMS (Schema Generator merge). Supports @graph or a single typed node.
 */
export default function JsonLd({ data }) {
  const serialized = useMemo(() => {
    if (!data || typeof data !== 'object') return ''
    try {
      if (Array.isArray(data['@graph']) && data['@graph'].length > 0) {
        return JSON.stringify(data)
      }
      if (data['@type'] || data['@context']) {
        return JSON.stringify(data)
      }
    } catch {
      return ''
    }
    return ''
  }, [data])

  useEffect(() => {
    if (!serialized) return undefined
    const el = document.createElement('script')
    el.type = 'application/ld+json'
    el.setAttribute('data-cms-json-ld', '1')
    el.textContent = serialized
    document.head.appendChild(el)
    return () => {
      el.remove()
    }
  }, [serialized])

  return null
}
